import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DateRangeFilter, Pagination, StatusBadge, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { DeliveryDto } from '../../../services/bh/models';
import { formatDateLocal, formatVnd } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
const PAGE_SIZE = 20;
const XuatHangPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [fromDate, setFromDate] = useState<string | undefined>();
  const [toDate, setToDate] = useState<string | undefined>();
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<DeliveryDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);
  React.useEffect(() => {
    let c = false; setLoading(true);
    const t = setTimeout(() => {
      bhService.getDeliveries({ fromDate, toDate, page, pageSize: PAGE_SIZE })
        .then(r => { if (!c) { setItems(r.items); setTotalCount(r.totalCount); } })
        .catch(e => { if (!c) dispatch(addToast({ message: e?.message ?? 'Lỗi', type: 'error' })); })
        .finally(() => { if (!c) setLoading(false); });
    }, 0);
    return () => { c = true; clearTimeout(t); };
  }, [fromDate, toDate, page, dispatch, reloadKey]);
  return (
    <div className={styles.page}>
      <h1 className={styles.title}>Phiếu xuất hàng</h1>
      <div className={styles.filtersBar} data-testid={`erp-xuat-hang-filters`}>
        <DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v: DateRangeValue) => { setFromDate(v.fromDate); setToDate(v.toDate); setPage(1); }} />
        <ListSearchRefreshButtons testIdPrefix="erp-xuat-hang" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>
      <div className={styles.tableCard}>
        {loading ? <div className={styles.loading}>Đang tải...</div> : (
          <table className={styles.table}>
            <thead><tr><th>Số phiếu</th><th>Ngày</th><th>KH</th><th>Kho</th><th className={styles.colRight}>Tổng</th><th>TT</th></tr></thead>
            <tbody>{items.map(r => (
              <tr key={r.id}><td><code>{r.code}</code></td><td>{formatDateLocal(r.deliveryDate)}</td><td>{r.customerName}</td><td>{r.warehouseName}</td>
              <td className={styles.colRight}>{formatVnd(r.totalAmount)}</td><td><StatusBadge status={r.status} /></td></tr>
            ))}</tbody>
          </table>
        )}
        {totalCount > 0 && <Pagination currentPage={page} totalPages={Math.ceil(totalCount/PAGE_SIZE)} totalCount={totalCount} pageSize={PAGE_SIZE} onPageChange={setPage} />}
      </div>
    </div>
  );
};
export default XuatHangPage;
